    37→func (a *OpenCodeAgent) DetectPresence() (bool, error) {
    38→	repoRoot, err := paths.RepoRoot()
    39→	if err != nil {
    40→		repoRoot = "."
    41→	}
    42→	// Check for .opencode directory or opencode.json config
    43→	if _, err := os.Stat(filepath.Join(repoRoot, ".opencode")); err == nil {
    44→		return true, nil
    45→	}
    46→	if _, err := os.Stat(filepath.Join(repoRoot, "opencode.json")); err == nil {
    47→		return true, nil
    48→	}
    49→	return false, nil
    50→}
