    53→
    54→func (a *OpenCodeAgent) ReadTranscript(sessionRef string) ([]byte, error) {
    55→	data, err := os.ReadFile(sessionRef) //nolint:gosec // Path from agent hook
    56→	if err != nil {
    57→		return nil, fmt.Errorf("failed to read opencode transcript: %w", err)
