    62→func (a *OpenCodeAgent) ChunkTranscript(content []byte, maxSize int) ([][]byte, error) {
    63→	// OpenCode uses JSONL (one message per line) — use the shared JSONL chunker.
    64→	chunks, err := agent.ChunkJSONL(content, maxSize)
    65→	if err != nil {
    66→		return nil, fmt.Errorf("failed to chunk opencode transcript: %w", err)
    67→	}
    68→	return chunks, nil
    69→}
