    82→// GetSessionDir returns the directory where Entire stores OpenCode session transcripts.
    83→// Transcripts are ephemeral handoff files between the TS plugin and the Go hook handler.
    84→// Once checkpointed, the data lives on git refs and the file is disposable.
    85→// Stored in os.TempDir()/entire-opencode/<sanitized-path>/ to avoid squatting on
    86→// OpenCode's own directories (~/.opencode/ is project-level, not home-level).
    87→func (a *OpenCodeAgent) GetSessionDir(repoPath string) (string, error) {
    88→	// Check for test environment override
    89→	if override := os.Getenv("ENTIRE_TEST_OPENCODE_PROJECT_DIR"); override != "" {
    90→		return override, nil
    91→	}
    92→
    93→	projectDir := SanitizePathForOpenCode(repoPath)
    94→	return filepath.Join(os.TempDir(), "entire-opencode", projectDir), nil
    95→}
    96→
    97→func (a *OpenCodeAgent) ResolveSessionFile(sessionDir, agentSessionID string) string {
    98→	return filepath.Join(sessionDir, agentSessionID+".jsonl")
