   101→func (a *OpenCodeAgent) ReadSession(input *agent.HookInput) (*agent.AgentSession, error) {
   102→	if input.SessionRef == "" {
   103→		return nil, errors.New("no session ref provided")
   104→	}
   105→	data, err := os.ReadFile(input.SessionRef)
   106→	if err != nil {
   107→		return nil, fmt.Errorf("failed to read session: %w", err)
   108→	}
   109→
   110→	// Parse to extract computed fields
   111→	modifiedFiles, err := ExtractModifiedFiles(data)
   112→	if err != nil {
   113→		// Non-fatal: we can still return the session without modified files
   114→		modifiedFiles = nil
   115→	}
   116→
   117→	return &agent.AgentSession{
   118→		AgentName:     a.Name(),
   119→		SessionID:     input.SessionID,
   120→		SessionRef:    input.SessionRef,
   121→		NativeData:    data,
   122→		ModifiedFiles: modifiedFiles,
   123→	}, nil
   124→}
   125→
   126→func (a *OpenCodeAgent) WriteSession(session *agent.AgentSession) error {
   127→	if session == nil {
   128→		return errors.New("nil session")
   129→	}
   130→	if session.SessionRef == "" {
   131→		return errors.New("no session ref to write to")
   132→	}
   133→	if len(session.NativeData) == 0 {
   134→		return errors.New("no session data to write")
   135→	}
   136→
   137→	// 1. Write JSONL file (for Entire's internal checkpoint use)
   138→	dir := filepath.Dir(session.SessionRef)
   139→	//nolint:gosec // G301: Session directory needs standard permissions
   140→	if err := os.MkdirAll(dir, 0o755); err != nil {
   141→		return fmt.Errorf("failed to create session directory: %w", err)
   142→	}
   143→	if err := os.WriteFile(session.SessionRef, session.NativeData, 0o600); err != nil {
   144→		return fmt.Errorf("failed to write session data: %w", err)
   145→	}
   146→
   147→	// 2. If we have export data, import the session into OpenCode.
   148→	//    This enables `opencode -s <id>` for both resume and rewind.
   149→	if len(session.ExportData) == 0 {
   150→		return nil // No export data — skip import (graceful degradation)
   151→	}
   152→
   153→	if err := a.importSessionIntoOpenCode(session.SessionID, session.ExportData); err != nil {
   154→		// Non-fatal: import is best-effort. The JSONL file is written,
   155→		// and the user can always run `opencode import <file>` manually.
   156→		fmt.Fprintf(os.Stderr, "warning: could not import session into OpenCode: %v\n", err)
   157→	}
   158→
   159→	return nil
   160→}
   161→
   162→// importSessionIntoOpenCode writes the export JSON to a temp file and runs
   163→// `opencode import` to restore the session into OpenCode's database.
   164→// For rewind (session already exists), the session is deleted first so the
   165→// reimport replaces it with the checkpoint-state messages.
   166→func (a *OpenCodeAgent) importSessionIntoOpenCode(sessionID string, exportData []byte) error {
   167→	// Delete the session first so reimport replaces it cleanly.
   168→	// opencode import uses ON CONFLICT DO NOTHING, so existing messages
   169→	// would be skipped without this step (breaking rewind).
   170→	// runOpenCodeSessionDelete treats "not found" as success.
   171→	if err := runOpenCodeSessionDelete(sessionID); err != nil {
   172→		return fmt.Errorf("failed to delete existing session: %w", err)
   173→	}
   174→
   175→	// Write export JSON to a temp file for opencode import
   176→	tmpFile, err := os.CreateTemp("", "entire-opencode-export-*.json")
   177→	if err != nil {
   178→		return fmt.Errorf("failed to create temp file: %w", err)
   179→	}
   180→	defer os.Remove(tmpFile.Name())
   181→
   182→	if _, err := tmpFile.Write(exportData); err != nil {
   183→		_ = tmpFile.Close()
   184→		return fmt.Errorf("failed to write export data: %w", err)
   185→	}
   186→	if err := tmpFile.Close(); err != nil {
   187→		return fmt.Errorf("failed to close temp file: %w", err)
   188→	}
   189→
   190→	return runOpenCodeImport(tmpFile.Name())
   191→}
   192→
   193→func (a *OpenCodeAgent) FormatResumeCommand(sessionID string) string {
   194→	if strings.TrimSpace(sessionID) == "" {
   195→		return "opencode"
   196→	}
   197→	return "opencode -s " + sessionID
   198→}
   199→
   200→// nonAlphanumericRegex matches any non-alphanumeric character.
   201→var nonAlphanumericRegex = regexp.MustCompile(`[^a-zA-Z0-9]`)
   202→
   203→// SanitizePathForOpenCode converts a path to a safe directory name.
   204→// Replaces any non-alphanumeric character with a dash (same approach as Claude/Gemini).
   205→func SanitizePathForOpenCode(path string) string {
   206→	return nonAlphanumericRegex.ReplaceAllString(path, "-")
   207→}
