     3→import (
     4→	"bufio"
     5→	"bytes"
     6→	"encoding/json"
     7→	"fmt"
     8→	"io"
     9→	"os"
    10→	"slices"
    11→
    12→	"github.com/entireio/cli/cmd/entire/cli/agent"
    13→)
    14→
    15→// Compile-time interface assertions
    16→var (
    17→	_ agent.TranscriptAnalyzer = (*OpenCodeAgent)(nil)
    18→	_ agent.TokenCalculator    = (*OpenCodeAgent)(nil)
    19→)
    20→
    21→// ParseMessages parses JSONL content (one Message per line) into a slice of Messages.
    22→func ParseMessages(data []byte) ([]Message, error) {
    23→	if len(data) == 0 {
    24→		return nil, nil
    25→	}
    26→
    27→	var messages []Message
    28→	reader := bufio.NewReader(bytes.NewReader(data))
    29→
    30→	for {
    31→		lineBytes, err := reader.ReadBytes('\n')
    32→		if err != nil && err != io.EOF {
    33→			return nil, fmt.Errorf("failed to read opencode transcript: %w", err)
    34→		}
    35→
    36→		if len(bytes.TrimSpace(lineBytes)) > 0 {
    37→			var msg Message
    38→			if jsonErr := json.Unmarshal(lineBytes, &msg); jsonErr == nil {
    39→				messages = append(messages, msg)
    40→			}
    41→		}
    42→
    43→		if err == io.EOF {
    44→			break
    45→		}
    46→	}
    47→
    48→	return messages, nil
    49→}
    50→
    51→// parseMessagesFromFile reads and parses a JSONL transcript file.
    52→func parseMessagesFromFile(path string) ([]Message, error) {
    53→	data, err := os.ReadFile(path) //nolint:gosec // Path from agent hook
    54→	if err != nil {
    55→		return nil, err //nolint:wrapcheck // Callers check os.IsNotExist on this error
    56→	}
    57→	return ParseMessages(data)
    58→}
    59→
    60→// GetTranscriptPosition returns the number of JSONL lines in the transcript.
    61→func (a *OpenCodeAgent) GetTranscriptPosition(path string) (int, error) {
    62→	messages, err := parseMessagesFromFile(path)
    63→	if err != nil {
    64→		if os.IsNotExist(err) {
    65→			return 0, nil
    66→		}
    67→		return 0, err
    68→	}
    69→	return len(messages), nil
    70→}
    71→
    72→// ExtractModifiedFilesFromOffset extracts files modified by tool calls from the given message offset.
    73→func (a *OpenCodeAgent) ExtractModifiedFilesFromOffset(path string, startOffset int) ([]string, int, error) {
    74→	messages, err := parseMessagesFromFile(path)
    75→	if err != nil {
    76→		if os.IsNotExist(err) {
    77→			return nil, 0, nil
    78→		}
    79→		return nil, 0, err
    80→	}
    81→
    82→	seen := make(map[string]bool)
    83→	var files []string
    84→
    85→	for i := startOffset; i < len(messages); i++ {
    86→		msg := messages[i]
    87→		if msg.Role != roleAssistant {
    88→			continue
    89→		}
    90→		for _, part := range msg.Parts {
    91→			if part.Type != "tool" || part.State == nil {
    92→				continue
    93→			}
    94→			if !slices.Contains(FileModificationTools, part.Tool) {
    95→				continue
    96→			}
    97→			filePath := extractFilePathFromInput(part.State.Input)
    98→			if filePath != "" && !seen[filePath] {
    99→				seen[filePath] = true
   100→				files = append(files, filePath)
   101→			}
   102→		}
   103→	}
   104→
   105→	return files, len(messages), nil
   106→}
   107→
   108→// ExtractModifiedFiles extracts modified file paths from raw JSONL transcript bytes.
   109→// This is the bytes-based equivalent of ExtractModifiedFilesFromOffset, used by ReadSession.
   110→func ExtractModifiedFiles(data []byte) ([]string, error) {
   111→	messages, err := ParseMessages(data)
   112→	if err != nil {
   113→		return nil, err
   114→	}
   115→
   116→	seen := make(map[string]bool)
   117→	var files []string
   118→
   119→	for _, msg := range messages {
   120→		if msg.Role != roleAssistant {
   121→			continue
   122→		}
   123→		for _, part := range msg.Parts {
   124→			if part.Type != "tool" || part.State == nil {
   125→				continue
   126→			}
   127→			if !slices.Contains(FileModificationTools, part.Tool) {
   128→				continue
   129→			}
   130→			filePath := extractFilePathFromInput(part.State.Input)
   131→			if filePath != "" && !seen[filePath] {
   132→				seen[filePath] = true
   133→				files = append(files, filePath)
   134→			}
   135→		}
   136→	}
   137→
   138→	return files, nil
   139→}
   140→
   141→// extractFilePathFromInput extracts the file path from a tool's input map.
   142→func extractFilePathFromInput(input map[string]interface{}) string {
   143→	for _, key := range []string{"file_path", "path", "file", "filename"} {
   144→		if v, ok := input[key]; ok {
   145→			if s, ok := v.(string); ok && s != "" {
   146→				return s
   147→			}
   148→		}
   149→	}
   150→	return ""
   151→}
   152→
   153→// ExtractPrompts extracts user prompt strings from the transcript starting at the given offset.
   154→func (a *OpenCodeAgent) ExtractPrompts(sessionRef string, fromOffset int) ([]string, error) {
   155→	messages, err := parseMessagesFromFile(sessionRef)
   156→	if err != nil {
   157→		if os.IsNotExist(err) {
   158→			return nil, nil
   159→		}
   160→		return nil, err
   161→	}
   162→
   163→	var prompts []string
   164→	for i := fromOffset; i < len(messages); i++ {
   165→		msg := messages[i]
   166→		if msg.Role == roleUser && msg.Content != "" {
   167→			prompts = append(prompts, msg.Content)
   168→		}
   169→	}
   170→
   171→	return prompts, nil
   172→}
   173→
   174→// ExtractSummary extracts the last assistant message content as a summary.
   175→func (a *OpenCodeAgent) ExtractSummary(sessionRef string) (string, error) {
   176→	messages, err := parseMessagesFromFile(sessionRef)
   177→	if err != nil {
   178→		if os.IsNotExist(err) {
   179→			return "", nil
   180→		}
   181→		return "", err
   182→	}
   183→
   184→	for i := len(messages) - 1; i >= 0; i-- {
   185→		msg := messages[i]
   186→		if msg.Role == roleAssistant && msg.Content != "" {
   187→			return msg.Content, nil
   188→		}
   189→	}
   190→
   191→	return "", nil
   192→}
   193→
   194→// ExtractAllUserPrompts extracts all user prompts from raw JSONL transcript bytes.
   195→// This is a package-level function used by the condensation path.
   196→func ExtractAllUserPrompts(data []byte) ([]string, error) {
   197→	messages, err := ParseMessages(data)
   198→	if err != nil {
   199→		return nil, err
   200→	}
   201→
   202→	var prompts []string
   203→	for _, msg := range messages {
   204→		if msg.Role == roleUser && msg.Content != "" {
   205→			prompts = append(prompts, msg.Content)
   206→		}
   207→	}
   208→	return prompts, nil
   209→}
