   211→// CalculateTokenUsageFromBytes computes token usage from raw JSONL transcript bytes
   212→// starting at the given message offset.
   213→// This is a package-level function used by the condensation path (which has bytes, not a file path).
   214→func CalculateTokenUsageFromBytes(data []byte, startMessageIndex int) *agent.TokenUsage {
   215→	messages, err := ParseMessages(data)
   216→	if err != nil || messages == nil {
   217→		return &agent.TokenUsage{}
   218→	}
   219→
   220→	usage := &agent.TokenUsage{}
   221→	for i := startMessageIndex; i < len(messages); i++ {
   222→		msg := messages[i]
   223→		if msg.Role != roleAssistant || msg.Tokens == nil {
   224→			continue
   225→		}
   226→		usage.InputTokens += msg.Tokens.Input
   227→		usage.OutputTokens += msg.Tokens.Output
   228→		usage.CacheReadTokens += msg.Tokens.Cache.Read
   229→		usage.CacheCreationTokens += msg.Tokens.Cache.Write
   230→		usage.APICallCount++
   231→	}
   232→
   233→	return usage
   234→}
   235→
   236→// CalculateTokenUsage computes token usage from assistant messages starting at the given offset.
   237→func (a *OpenCodeAgent) CalculateTokenUsage(sessionRef string, fromOffset int) (*agent.TokenUsage, error) {
   238→	messages, err := parseMessagesFromFile(sessionRef)
   239→	if err != nil {
   240→		if os.IsNotExist(err) {
   241→			return nil, nil //nolint:nilnil // nil usage for nonexistent file is expected
   242→		}
   243→		return nil, fmt.Errorf("failed to parse transcript for token usage: %w", err)
   244→	}
   245→
   246→	usage := &agent.TokenUsage{}
   247→	for i := fromOffset; i < len(messages); i++ {
   248→		msg := messages[i]
   249→		if msg.Role != roleAssistant || msg.Tokens == nil {
   250→			continue
   251→		}
   252→		usage.InputTokens += msg.Tokens.Input
   253→		usage.OutputTokens += msg.Tokens.Output
   254→		usage.CacheReadTokens += msg.Tokens.Cache.Read
   255→		usage.CacheCreationTokens += msg.Tokens.Cache.Write
   256→		usage.APICallCount++
   257→	}
   258→
   259→	return usage, nil
   260→}
