   110→// handleLifecycleTurnStart handles turn start: captures pre-prompt state,
   111→// ensures strategy setup, initializes session.
   112→func handleLifecycleTurnStart(ag agent.Agent, event *agent.Event) error {
   113→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "lifecycle"), ag.Name())
   114→	logging.Info(logCtx, "turn-start",
   115→		slog.String("event", event.Type.String()),
   116→		slog.String("session_id", event.SessionID),
   117→		slog.String("session_ref", event.SessionRef),
   118→	)
   119→
   120→	sessionID := event.SessionID
   121→	if sessionID == "" {
   122→		return fmt.Errorf("no session_id in %s event", event.Type)
   123→	}
   124→	if err := validation.ValidateSessionID(sessionID); err != nil {
   125→		return fmt.Errorf("invalid %s event: %w", event.Type, err)
   126→	}
   127→
   128→	// Capture pre-prompt state (including transcript position via TranscriptAnalyzer)
   129→	if err := CapturePrePromptState(ag, sessionID, event.SessionRef); err != nil {
   130→		return err
   131→	}
   132→
   133→	// Ensure strategy setup and initialize session
   134→	strat := GetStrategy()
   135→
   136→	if err := strat.EnsureSetup(); err != nil {
   137→		fmt.Fprintf(os.Stderr, "Warning: failed to ensure strategy setup: %v\n", err)
   138→	}
   139→
   140→	if initializer, ok := strat.(strategy.SessionInitializer); ok {
   141→		agentType := ag.Type()
   142→		if err := initializer.InitializeSession(sessionID, agentType, event.SessionRef, event.Prompt); err != nil {
   143→			fmt.Fprintf(os.Stderr, "Warning: failed to initialize session state: %v\n", err)
   144→		}
   145→	}
   146→
   147→	return nil
   148→}
   149→
   150→// handleLifecycleTurnEnd handles turn end: validates transcript, extracts metadata,
   151→// detects file changes, saves step + checkpoint, transitions phase.
   152→//
   153→//nolint:maintidx // high complexity due to sequential orchestration of 8 steps (validation, extraction, file detection, filtering, token calc, step save, phase transition, cleanup) - splitting would obscure the flow
   154→func handleLifecycleTurnEnd(ag agent.Agent, event *agent.Event) error {
   155→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "lifecycle"), ag.Name())
   156→	logging.Info(logCtx, "turn-end",
   157→		slog.String("event", event.Type.String()),
   158→		slog.String("session_id", event.SessionID),
   159→		slog.String("session_ref", event.SessionRef),
   160→	)
   161→
   162→	sessionID := event.SessionID
   163→	if sessionID == "" {
   164→		sessionID = unknownSessionID
   165→	}
   166→
   167→	transcriptRef := event.SessionRef
   168→	if transcriptRef == "" {
   169→		return errors.New("transcript file not specified")
   170→	}
   171→	if !fileExists(transcriptRef) {
   172→		return fmt.Errorf("transcript file not found: %s", transcriptRef)
   173→	}
   174→
   175→	// Early check: bail out quickly if the repo has no commits yet.
   176→	if repo, err := strategy.OpenRepository(); err == nil && strategy.IsEmptyRepository(repo) {
   177→		fmt.Fprintln(os.Stderr, "Entire: skipping checkpoint. Will activate after first commit.")
   178→		return NewSilentError(strategy.ErrEmptyRepository)
   179→	}
   180→
   181→	// Create session metadata directory
   182→	sessionDir := paths.SessionMetadataDirFromSessionID(sessionID)
   183→	sessionDirAbs, err := paths.AbsPath(sessionDir)
   184→	if err != nil {
   185→		sessionDirAbs = sessionDir
   186→	}
   187→	if err := os.MkdirAll(sessionDirAbs, 0o750); err != nil {
   188→		return fmt.Errorf("failed to create session directory: %w", err)
   189→	}
   190→
   191→	// If agent implements TranscriptPreparer, wait for transcript to be ready
   192→	if preparer, ok := ag.(agent.TranscriptPreparer); ok {
   193→		if err := preparer.PrepareTranscript(transcriptRef); err != nil {
   194→			fmt.Fprintf(os.Stderr, "Warning: failed to prepare transcript: %v\n", err)
   195→		}
   196→	}
   197→
   198→	// Copy transcript to session directory
   199→	transcriptData, err := ag.ReadTranscript(transcriptRef)
   200→	if err != nil {
   201→		return fmt.Errorf("failed to read transcript: %w", err)
   202→	}
   203→	logFile := filepath.Join(sessionDirAbs, paths.TranscriptFileName)
   204→	if err := os.WriteFile(logFile, transcriptData, 0o600); err != nil {
   205→		return fmt.Errorf("failed to write transcript: %w", err)
   206→	}
   207→	fmt.Fprintf(os.Stderr, "Copied transcript to: %s\n", sessionDir+"/"+paths.TranscriptFileName)
   208→
   209→	// Copy export JSON if it exists alongside the transcript (written by OpenCode plugin).
   210→	// This is used by `opencode import` during resume/rewind to restore the session
   211→	// into OpenCode's SQLite database with the original session ID.
   212→	exportSrc := strings.TrimSuffix(transcriptRef, filepath.Ext(transcriptRef)) + ".export.json"
   213→	if exportData, readErr := os.ReadFile(exportSrc); readErr == nil { //nolint:gosec // Path derived from agent hook
   214→		exportDest := filepath.Join(sessionDirAbs, paths.ExportDataFileName)
   215→		if writeErr := os.WriteFile(exportDest, exportData, 0o600); writeErr != nil {
   216→			fmt.Fprintf(os.Stderr, "Warning: failed to write export data: %v\n", writeErr)
   217→		}
   218→	}
   219→
   220→	// Load pre-prompt state (captured on TurnStart)
   221→	preState, err := LoadPrePromptState(sessionID)
   222→	if err != nil {
   223→		fmt.Fprintf(os.Stderr, "Warning: failed to load pre-prompt state: %v\n", err)
   224→	}
   225→
   226→	// Determine transcript offset
   227→	transcriptOffset := resolveTranscriptOffset(preState, sessionID)
   228→
   229→	// Extract metadata via agent interface (prompts, summary, modified files)
   230→	var allPrompts []string
   231→	var summary string
   232→	var modifiedFiles []string
   233→	var newTranscriptPosition int
   234→
   235→	// Compute subagents directory for agents that support subagent extraction.
   236→	// Subagent transcripts live in <transcriptDir>/<modelSessionID>/subagents/
   237→	subagentsDir := filepath.Join(filepath.Dir(transcriptRef), event.SessionID, "subagents")
   238→
   239→	if analyzer, ok := ag.(agent.TranscriptAnalyzer); ok {
   240→		// Extract prompts
   241→		if prompts, promptErr := analyzer.ExtractPrompts(transcriptRef, transcriptOffset); promptErr != nil {
   242→			fmt.Fprintf(os.Stderr, "Warning: failed to extract prompts: %v\n", promptErr)
   243→		} else {
   244→			allPrompts = prompts
   245→		}
   246→
   247→		// Extract summary
   248→		if s, sumErr := analyzer.ExtractSummary(transcriptRef); sumErr != nil {
   249→			fmt.Fprintf(os.Stderr, "Warning: failed to extract summary: %v\n", sumErr)
   250→		} else {
   251→			summary = s
   252→		}
   253→
   254→		// Extract modified files - prefer SubagentAwareExtractor if available to include subagent files
   255→		if subagentExtractor, subOk := ag.(agent.SubagentAwareExtractor); subOk {
   256→			if files, fileErr := subagentExtractor.ExtractAllModifiedFiles(transcriptRef, transcriptOffset, subagentsDir); fileErr != nil {
   257→				fmt.Fprintf(os.Stderr, "Warning: failed to extract modified files (with subagents): %v\n", fileErr)
   258→			} else {
   259→				modifiedFiles = files
   260→			}
   261→			// Get position from basic analyzer
   262→			if _, pos, posErr := analyzer.ExtractModifiedFilesFromOffset(transcriptRef, transcriptOffset); posErr == nil {
   263→				newTranscriptPosition = pos
   264→			}
   265→		} else {
   266→			// Fall back to basic extraction (main transcript only)
   267→			if files, pos, fileErr := analyzer.ExtractModifiedFilesFromOffset(transcriptRef, transcriptOffset); fileErr != nil {
   268→				fmt.Fprintf(os.Stderr, "Warning: failed to extract modified files: %v\n", fileErr)
   269→			} else {
   270→				modifiedFiles = files
   271→				newTranscriptPosition = pos
   272→			}
   273→		}
   274→	}
   275→
   276→	// Write prompts file
   277→	promptFile := filepath.Join(sessionDirAbs, paths.PromptFileName)
   278→	promptContent := strings.Join(allPrompts, "\n\n---\n\n")
   279→	if err := os.WriteFile(promptFile, []byte(promptContent), 0o600); err != nil {
   280→		return fmt.Errorf("failed to write prompt file: %w", err)
   281→	}
   282→	fmt.Fprintf(os.Stderr, "Extracted %d prompt(s) to: %s\n", len(allPrompts), sessionDir+"/"+paths.PromptFileName)
   283→
   284→	// Write summary file
   285→	summaryFile := filepath.Join(sessionDirAbs, paths.SummaryFileName)
   286→	if err := os.WriteFile(summaryFile, []byte(summary), 0o600); err != nil {
   287→		return fmt.Errorf("failed to write summary file: %w", err)
   288→	}
   289→	fmt.Fprintf(os.Stderr, "Extracted summary to: %s\n", sessionDir+"/"+paths.SummaryFileName)
   290→
   291→	// Generate commit message from last prompt
   292→	lastPrompt := ""
   293→	if len(allPrompts) > 0 {
   294→		lastPrompt = allPrompts[len(allPrompts)-1]
   295→	}
   296→	commitMessage := generateCommitMessage(lastPrompt)
   297→	fmt.Fprintf(os.Stderr, "Using commit message: %s\n", commitMessage)
   298→
   299→	// Get repo root for path normalization
   300→	repoRoot, err := paths.RepoRoot()
   301→	if err != nil {
   302→		return fmt.Errorf("failed to get repo root: %w", err)
   303→	}
   304→
   305→	var preUntrackedFiles []string
   306→	if preState != nil {
   307→		fmt.Fprintf(os.Stderr, "Pre-prompt state: %d pre-existing untracked files\n", len(preState.UntrackedFiles))
   308→		preUntrackedFiles = preState.PreUntrackedFiles()
   309→	}
   310→
   311→	// Detect file changes via git status
   312→	changes, err := DetectFileChanges(preUntrackedFiles)
   313→	if err != nil {
   314→		fmt.Fprintf(os.Stderr, "Warning: failed to compute file changes: %v\n", err)
   315→	}
   316→
   317→	// Filter and normalize all paths
   318→	relModifiedFiles := FilterAndNormalizePaths(modifiedFiles, repoRoot)
   319→	var relNewFiles, relDeletedFiles []string
   320→	if changes != nil {
   321→		relNewFiles = FilterAndNormalizePaths(changes.New, repoRoot)
   322→		relDeletedFiles = FilterAndNormalizePaths(changes.Deleted, repoRoot)
   323→	}
   324→
   325→	// Filter transcript-extracted files to exclude files already committed to HEAD.
   326→	// When an agent commits files mid-turn, those files are condensed by PostCommit
   327→	// and should not be re-added to FilesTouched by SaveStep. A file is "committed"
   328→	// if it exists in HEAD with the same content as the working tree.
   329→	relModifiedFiles = filterToUncommittedFiles(relModifiedFiles, repoRoot)
   330→
   331→	// Check if there are any changes
   332→	totalChanges := len(relModifiedFiles) + len(relNewFiles) + len(relDeletedFiles)
   333→	if totalChanges == 0 {
   334→		fmt.Fprintf(os.Stderr, "No files were modified during this session\n")
   335→		fmt.Fprintf(os.Stderr, "Skipping commit\n")
   336→		transitionSessionTurnEnd(sessionID)
   337→		if cleanupErr := CleanupPrePromptState(sessionID); cleanupErr != nil {
   338→			fmt.Fprintf(os.Stderr, "Warning: failed to cleanup pre-prompt state: %v\n", cleanupErr)
   339→		}
   340→		return nil
   341→	}
   342→
   343→	// Log file changes
   344→	logFileChanges(relModifiedFiles, relNewFiles, relDeletedFiles)
   345→
   346→	// Create context file
   347→	contextFile := filepath.Join(sessionDirAbs, paths.ContextFileName)
   348→	if err := createContextFile(contextFile, commitMessage, sessionID, allPrompts, summary); err != nil {
   349→		return fmt.Errorf("failed to create context file: %w", err)
   350→	}
   351→	fmt.Fprintf(os.Stderr, "Created context file: %s\n", sessionDir+"/"+paths.ContextFileName)
   352→
   353→	// Get git author
   354→	author, err := GetGitAuthor()
   355→	if err != nil {
   356→		return fmt.Errorf("failed to get git author: %w", err)
   357→	}
   358→
   359→	// Get strategy and agent type
   360→	strat := GetStrategy()
   361→	agentType := ag.Type()
   362→
   363→	// Get transcript position/identifier from pre-prompt state
   364→	var transcriptIdentifierAtStart string
   365→	var transcriptLinesAtStart int
   366→	if preState != nil {
   367→		transcriptIdentifierAtStart = preState.LastTranscriptIdentifier
   368→		transcriptLinesAtStart = preState.TranscriptOffset
   369→	}
   370→
   371→	// Calculate token usage - prefer SubagentAwareExtractor to include subagent tokens
   372→	var tokenUsage *agent.TokenUsage
   373→	if subagentExtractor, ok := ag.(agent.SubagentAwareExtractor); ok {
   374→		usage, tokenErr := subagentExtractor.CalculateTotalTokenUsage(transcriptRef, transcriptLinesAtStart, subagentsDir)
   375→		if tokenErr != nil {
   376→			fmt.Fprintf(os.Stderr, "Warning: failed to calculate token usage (with subagents): %v\n", tokenErr)
   377→		} else {
   378→			tokenUsage = usage
   379→		}
   380→	} else if calculator, ok := ag.(agent.TokenCalculator); ok {
   381→		// Fall back to basic token calculation (main transcript only)
   382→		usage, tokenErr := calculator.CalculateTokenUsage(transcriptRef, transcriptLinesAtStart)
   383→		if tokenErr != nil {
   384→			fmt.Fprintf(os.Stderr, "Warning: failed to calculate token usage: %v\n", tokenErr)
   385→		} else {
   386→			tokenUsage = usage
   387→		}
   388→	}
   389→
   390→	// Build fully-populated step context and delegate to strategy
   391→	ctx := strategy.StepContext{
   392→		SessionID:                sessionID,
   393→		ModifiedFiles:            relModifiedFiles,
   394→		NewFiles:                 relNewFiles,
   395→		DeletedFiles:             relDeletedFiles,
   396→		MetadataDir:              sessionDir,
   397→		MetadataDirAbs:           sessionDirAbs,
   398→		CommitMessage:            commitMessage,
   399→		TranscriptPath:           transcriptRef,
   400→		AuthorName:               author.Name,
   401→		AuthorEmail:              author.Email,
   402→		AgentType:                agentType,
   403→		StepTranscriptIdentifier: transcriptIdentifierAtStart,
   404→		StepTranscriptStart:      transcriptLinesAtStart,
   405→		TokenUsage:               tokenUsage,
   406→	}
   407→
   408→	if err := strat.SaveStep(ctx); err != nil {
   409→		return fmt.Errorf("failed to save step: %w", err)
   410→	}
   411→
   412→	// Update session state transcript position for auto-commit strategy
   413→	if strat.Name() == strategy.StrategyNameAutoCommit && newTranscriptPosition > 0 {
   414→		updateAutoCommitTranscriptPosition(sessionID, newTranscriptPosition)
   415→	}
   416→
   417→	// Transition session phase and cleanup
   418→	transitionSessionTurnEnd(sessionID)
   419→	if cleanupErr := CleanupPrePromptState(sessionID); cleanupErr != nil {
   420→		fmt.Fprintf(os.Stderr, "Warning: failed to cleanup pre-prompt state: %v\n", cleanupErr)
   421→	}
   422→
   423→	return nil
   424→}
   425→
   426→// handleLifecycleCompaction handles context compaction: saves current progress
   427→// but stays in ACTIVE phase (unlike TurnEnd which transitions to IDLE).
   428→// Also resets the transcript offset since the transcript may be truncated.
   429→func handleLifecycleCompaction(ag agent.Agent, event *agent.Event) error {
   430→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "lifecycle"), ag.Name())
   431→	logging.Info(logCtx, "compaction",
   432→		slog.String("event", event.Type.String()),
   433→		slog.String("session_id", event.SessionID),
   434→	)
   435→
   436→	// Fire EventCompaction to trigger ActionCondenseIfFilesTouched (stays in ACTIVE)
   437→	sessionID := event.SessionID
   438→	sessionState, loadErr := strategy.LoadSessionState(sessionID)
   439→	if loadErr != nil {
   440→		fmt.Fprintf(os.Stderr, "Warning: failed to load session state for compaction: %v\n", loadErr)
   441→	}
   442→	if sessionState != nil {
   443→		if transErr := strategy.TransitionAndLog(sessionState, session.EventCompaction, session.TransitionContext{}, session.NoOpActionHandler{}); transErr != nil {
   444→			fmt.Fprintf(os.Stderr, "Warning: compaction transition failed: %v\n", transErr)
   445→		}
   446→
   447→		// Reset transcript offset since the transcript may be truncated/reorganized
   448→		sessionState.CheckpointTranscriptStart = 0
   449→
   450→		if saveErr := strategy.SaveSessionState(sessionState); saveErr != nil {
   451→			fmt.Fprintf(os.Stderr, "Warning: failed to save session state after compaction: %v\n", saveErr)
   452→		}
   453→	}
   454→
   455→	fmt.Fprintf(os.Stderr, "Context compaction: transcript offset reset\n")
   456→	return nil
   457→}
