   500→// handleLifecycleSubagentEnd handles subagent end: detects changes, saves task checkpoint.
   501→func handleLifecycleSubagentEnd(ag agent.Agent, event *agent.Event) error {
   502→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "lifecycle"), ag.Name())
   503→	logging.Info(logCtx, "subagent-end",
   504→		slog.String("event", event.Type.String()),
   505→		slog.String("session_id", event.SessionID),
   506→		slog.String("tool_use_id", event.ToolUseID),
   507→		slog.String("subagent_id", event.SubagentID),
   508→	)
   509→
   510→	// Extract subagent type and description from tool input
   511→	subagentType, taskDescription := ParseSubagentTypeAndDescription(event.ToolInput)
   512→
   513→	// Determine subagent transcript path
   514→	transcriptDir := filepath.Dir(event.SessionRef)
   515→	var subagentTranscriptPath string
   516→	if event.SubagentID != "" {
   517→		subagentTranscriptPath = AgentTranscriptPath(transcriptDir, event.SubagentID)
   518→		if !fileExists(subagentTranscriptPath) {
   519→			subagentTranscriptPath = ""
   520→		}
   521→	}
   522→
   523→	// Log context
   524→	fmt.Fprintf(os.Stderr, "[entire] Subagent completed\n")
   525→	fmt.Fprintf(os.Stderr, "  Session ID: %s\n", event.SessionID)
   526→	fmt.Fprintf(os.Stderr, "  Tool Use ID: %s\n", event.ToolUseID)
   527→	if event.SubagentID != "" {
   528→		fmt.Fprintf(os.Stderr, "  Agent ID: %s\n", event.SubagentID)
   529→	}
   530→	if subagentTranscriptPath != "" {
   531→		fmt.Fprintf(os.Stderr, "  Subagent Transcript: %s\n", subagentTranscriptPath)
   532→	}
   533→
   534→	// Extract modified files from subagent transcript
   535→	var modifiedFiles []string
   536→	if analyzer, ok := ag.(agent.TranscriptAnalyzer); ok {
   537→		transcriptToScan := event.SessionRef
   538→		if subagentTranscriptPath != "" {
   539→			transcriptToScan = subagentTranscriptPath
   540→		}
   541→		if files, _, fileErr := analyzer.ExtractModifiedFilesFromOffset(transcriptToScan, 0); fileErr != nil {
   542→			fmt.Fprintf(os.Stderr, "Warning: failed to extract modified files from subagent: %v\n", fileErr)
   543→		} else {
   544→			modifiedFiles = files
   545→		}
   546→	}
   547→
   548→	// Load pre-task state and detect file changes
   549→	preState, err := LoadPreTaskState(event.ToolUseID)
   550→	if err != nil {
   551→		fmt.Fprintf(os.Stderr, "Warning: failed to load pre-task state: %v\n", err)
   552→	}
   553→	var preUntrackedFiles []string
   554→	if preState != nil {
   555→		preUntrackedFiles = preState.PreUntrackedFiles()
   556→	}
   557→	changes, err := DetectFileChanges(preUntrackedFiles)
   558→	if err != nil {
   559→		fmt.Fprintf(os.Stderr, "Warning: failed to compute file changes: %v\n", err)
   560→	}
   561→
   562→	// Get repo root and normalize paths
   563→	repoRoot, err := paths.RepoRoot()
   564→	if err != nil {
   565→		return fmt.Errorf("failed to get repo root: %w", err)
   566→	}
   567→
   568→	relModifiedFiles := FilterAndNormalizePaths(modifiedFiles, repoRoot)
   569→	var relNewFiles, relDeletedFiles []string
   570→	if changes != nil {
   571→		relNewFiles = FilterAndNormalizePaths(changes.New, repoRoot)
   572→		relDeletedFiles = FilterAndNormalizePaths(changes.Deleted, repoRoot)
   573→	}
   574→
   575→	// If no changes, skip
   576→	if len(relModifiedFiles) == 0 && len(relNewFiles) == 0 && len(relDeletedFiles) == 0 {
   577→		fmt.Fprintf(os.Stderr, "[entire] No file changes detected, skipping task checkpoint\n")
   578→		_ = CleanupPreTaskState(event.ToolUseID) //nolint:errcheck // best-effort cleanup
   579→		return nil
   580→	}
   581→
   582→	// Find checkpoint UUID from main transcript (best-effort)
   583→	var checkpointUUID string
   584→	// Use the existing CLI-level checkpoint UUID finder
   585→	mainLines, _, _ := parseTranscriptForCheckpointUUID(event.SessionRef) //nolint:errcheck // best-effort
   586→	if mainLines != nil {
   587→		checkpointUUID, _ = FindCheckpointUUID(mainLines, event.ToolUseID)
   588→	}
   589→
   590→	// Get git author
   591→	author, err := GetGitAuthor()
   592→	if err != nil {
   593→		return fmt.Errorf("failed to get git author: %w", err)
   594→	}
   595→
   596→	// Build task checkpoint context
   597→	strat := GetStrategy()
   598→	agentType := ag.Type()
   599→
   600→	ctx := strategy.TaskStepContext{
   601→		SessionID:              event.SessionID,
   602→		ToolUseID:              event.ToolUseID,
   603→		AgentID:                event.SubagentID,
   604→		ModifiedFiles:          relModifiedFiles,
   605→		NewFiles:               relNewFiles,
   606→		DeletedFiles:           relDeletedFiles,
   607→		TranscriptPath:         event.SessionRef,
   608→		SubagentTranscriptPath: subagentTranscriptPath,
   609→		CheckpointUUID:         checkpointUUID,
   610→		AuthorName:             author.Name,
   611→		AuthorEmail:            author.Email,
   612→		SubagentType:           subagentType,
   613→		TaskDescription:        taskDescription,
   614→		AgentType:              agentType,
   615→	}
   616→
   617→	if err := strat.SaveTaskStep(ctx); err != nil {
   618→		return fmt.Errorf("failed to save task step: %w", err)
   619→	}
   620→
   621→	_ = CleanupPreTaskState(event.ToolUseID) //nolint:errcheck // best-effort cleanup
   622→	return nil
   623→}
