   627→// resolveTranscriptOffset determines the transcript offset to use for parsing.
   628→// Prefers pre-prompt state, falls back to session state.
   629→func resolveTranscriptOffset(preState *PrePromptState, sessionID string) int {
   630→	if preState != nil && preState.TranscriptOffset > 0 {
   631→		fmt.Fprintf(os.Stderr, "Pre-prompt state found: parsing transcript from offset %d\n", preState.TranscriptOffset)
   632→		return preState.TranscriptOffset
   633→	}
   634→
   635→	// Fall back to session state (e.g., auto-commit strategy updates it after each save)
   636→	sessionState, loadErr := strategy.LoadSessionState(sessionID)
   637→	if loadErr != nil {
   638→		fmt.Fprintf(os.Stderr, "Warning: failed to load session state: %v\n", loadErr)
   639→		return 0
   640→	}
   641→	if sessionState != nil && sessionState.CheckpointTranscriptStart > 0 {
   642→		fmt.Fprintf(os.Stderr, "Session state found: parsing transcript from offset %d\n", sessionState.CheckpointTranscriptStart)
   643→		return sessionState.CheckpointTranscriptStart
   644→	}
   645→
   646→	return 0
   647→}
