   649→// updateAutoCommitTranscriptPosition updates the session state with the new transcript position
   650→// for the auto-commit strategy.
   651→func updateAutoCommitTranscriptPosition(sessionID string, newPosition int) {
   652→	sessionState, loadErr := strategy.LoadSessionState(sessionID)
   653→	if loadErr != nil {
   654→		fmt.Fprintf(os.Stderr, "Warning: failed to load session state: %v\n", loadErr)
   655→		return
   656→	}
   657→	if sessionState == nil {
   658→		sessionState = &strategy.SessionState{
   659→			SessionID: sessionID,
   660→		}
   661→	}
   662→	sessionState.CheckpointTranscriptStart = newPosition
   663→	sessionState.StepCount++
   664→	if updateErr := strategy.SaveSessionState(sessionState); updateErr != nil {
   665→		fmt.Fprintf(os.Stderr, "Warning: failed to update session state: %v\n", updateErr)
   666→	} else {
   667→		fmt.Fprintf(os.Stderr, "Updated session state: transcript position=%d, checkpoint=%d\n",
   668→			newPosition, sessionState.StepCount)
   669→	}
   670→}
