   672→// createContextFile creates a context.md file for the session checkpoint.
   673→// This is a unified version that works for all agents.
   674→func createContextFile(contextFile, commitMessage, sessionID string, prompts []string, summary string) error {
   675→	var sb strings.Builder
   676→
   677→	sb.WriteString("# Session Context\n\n")
   678→	fmt.Fprintf(&sb, "Session ID: %s\n", sessionID)
   679→	fmt.Fprintf(&sb, "Commit Message: %s\n\n", commitMessage)
   680→
   681→	if len(prompts) > 0 {
   682→		sb.WriteString("## Prompts\n\n")
   683→		for i, p := range prompts {
   684→			fmt.Fprintf(&sb, "### Prompt %d\n\n%s\n\n", i+1, p)
   685→		}
   686→	}
   687→
   688→	if summary != "" {
   689→		sb.WriteString("## Summary\n\n")
   690→		sb.WriteString(summary)
   691→		sb.WriteString("\n")
   692→	}
   693→
   694→	if err := os.WriteFile(contextFile, []byte(sb.String()), 0o600); err != nil {
   695→		return fmt.Errorf("failed to write context file: %w", err)
   696→	}
   697→	return nil
   698→}
