   700→// parseTranscriptForCheckpointUUID is a thin wrapper around transcript parsing for checkpoint UUID lookup.
   701→// Returns parsed transcript lines for use with FindCheckpointUUID.
   702→func parseTranscriptForCheckpointUUID(transcriptPath string) ([]transcriptLine, int, error) {
   703→	lines, total, err := transcript.ParseFromFileAtLine(transcriptPath, 0)
   704→	if err != nil {
   705→		return nil, 0, fmt.Errorf("parsing transcript for checkpoint UUID: %w", err)
