   710→// transitionSessionTurnEnd transitions the session phase to IDLE and dispatches turn-end actions.
   711→func transitionSessionTurnEnd(sessionID string) {
   712→	turnState, loadErr := strategy.LoadSessionState(sessionID)
   713→	if loadErr != nil {
   714→		fmt.Fprintf(os.Stderr, "Warning: failed to load session state for turn end: %v\n", loadErr)
   715→		return
   716→	}
   717→	if turnState == nil {
   718→		return
   719→	}
   720→	if err := strategy.TransitionAndLog(turnState, session.EventTurnEnd, session.TransitionContext{}, session.NoOpActionHandler{}); err != nil {
   721→		fmt.Fprintf(os.Stderr, "Warning: turn-end transition failed: %v\n", err)
   722→	}
   723→
   724→	// Always dispatch to strategy for turn-end handling. The strategy reads
   725→	// work items from state (e.g. TurnCheckpointIDs), not the action list.
   726→	strat := GetStrategy()
   727→	if handler, ok := strat.(strategy.TurnEndHandler); ok {
   728→		if err := handler.HandleTurnEnd(turnState); err != nil {
   729→			fmt.Fprintf(os.Stderr, "Warning: turn-end action dispatch failed: %v\n", err)
   730→		}
   731→	}
   732→
   733→	if updateErr := strategy.SaveSessionState(turnState); updateErr != nil {
   734→		fmt.Fprintf(os.Stderr, "Warning: failed to update session phase on turn end: %v\n", updateErr)
   735→	}
   736→}
   737→
   738→// markSessionEnded transitions the session to ENDED phase via the state machine.
   739→func markSessionEnded(sessionID string) error {
   740→	state, err := strategy.LoadSessionState(sessionID)
   741→	if err != nil {
   742→		return fmt.Errorf("failed to load session state: %w", err)
   743→	}
   744→	if state == nil {
   745→		return nil // No state file, nothing to update
   746→	}
   747→
   748→	if transErr := strategy.TransitionAndLog(state, session.EventSessionStop, session.TransitionContext{}, session.NoOpActionHandler{}); transErr != nil {
   749→		fmt.Fprintf(os.Stderr, "Warning: session stop transition failed: %v\n", transErr)
   750→	}
   751→
   752→	now := time.Now()
   753→	state.EndedAt = &now
   754→
   755→	if err := strategy.SaveSessionState(state); err != nil {
   756→		return fmt.Errorf("failed to save session state: %w", err)
   757→	}
   758→	return nil
   759→}
