   761→// logFileChanges logs the files modified, created, and deleted during a session.
   762→func logFileChanges(modified, newFiles, deleted []string) {
   763→	fmt.Fprintf(os.Stderr, "Files modified during session (%d):\n", len(modified))
   764→	for _, file := range modified {
   765→		fmt.Fprintf(os.Stderr, "  - %s\n", file)
   766→	}
   767→	if len(newFiles) > 0 {
   768→		fmt.Fprintf(os.Stderr, "New files created (%d):\n", len(newFiles))
   769→		for _, file := range newFiles {
   770→			fmt.Fprintf(os.Stderr, "  - %s\n", file)
   771→		}
   772→	}
   773→	if len(deleted) > 0 {
   774→		fmt.Fprintf(os.Stderr, "Files deleted (%d):\n", len(deleted))
   775→		for _, file := range deleted {
   776→			fmt.Fprintf(os.Stderr, "  - %s\n", file)
   777→		}
   778→	}
   779→}
