    83→// ResolveSessionFile returns the path to a Gemini session file.
    84→// Gemini names files as session-<date>-<shortid>.json where shortid is the first 8 chars
    85→// of the session UUID. This searches for an existing file matching the pattern, falling
    86→// back to constructing a filename matching Gemini's convention if no match is found.
    87→func (g *GeminiCLIAgent) ResolveSessionFile(sessionDir, agentSessionID string) string {
    88→	// Try to find existing file matching Gemini's naming convention:
    89→	// session-*-<first8chars>.json
    90→	shortID := agentSessionID
    91→	if len(shortID) > 8 {
    92→		shortID = shortID[:8]
    93→	}
    94→
    95→	pattern := filepath.Join(sessionDir, "session-*-"+shortID+".json")
    96→	matches, err := filepath.Glob(pattern)
    97→	if err == nil && len(matches) > 0 {
    98→		// Return the most recent match (last alphabetically, since date is in the name)
    99→		return matches[len(matches)-1]
   100→	}
   101→
   102→	// Fallback: construct filename matching Gemini's convention: session-<timestamp>-<id[:8]>.json
   103→	timestamp := time.Now().UTC().Format("2006-01-02T15-04")
   104→	return filepath.Join(sessionDir, "session-"+timestamp+"-"+shortID+".json")
   105→}
