   125→// ReadSession reads a session from Gemini's storage (JSON transcript file).
   126→// The session data is stored in NativeData as raw JSON bytes.
   127→func (g *GeminiCLIAgent) ReadSession(input *agent.HookInput) (*agent.AgentSession, error) {
   128→	if input.SessionRef == "" {
   129→		return nil, errors.New("session reference (transcript path) is required")
   130→	}
   131→
   132→	// Read the raw JSON file
   133→	data, err := os.ReadFile(input.SessionRef)
   134→	if err != nil {
   135→		return nil, fmt.Errorf("failed to read transcript: %w", err)
   136→	}
   137→
   138→	// Parse to extract computed fields
   139→	modifiedFiles, err := ExtractModifiedFiles(data)
   140→	if err != nil {
   141→		// Non-fatal: we can still return the session without modified files
   142→		modifiedFiles = nil
   143→	}
   144→
   145→	return &agent.AgentSession{
   146→		SessionID:     input.SessionID,
   147→		AgentName:     g.Name(),
   148→		SessionRef:    input.SessionRef,
   149→		StartTime:     time.Now(),
   150→		NativeData:    data,
   151→		ModifiedFiles: modifiedFiles,
   152→	}, nil
   153→}
