   155→// WriteSession writes a session to Gemini's storage (JSON transcript file).
   156→// Uses the NativeData field which contains raw JSON bytes.
   157→func (g *GeminiCLIAgent) WriteSession(session *agent.AgentSession) error {
   158→	if session == nil {
   159→		return errors.New("session is nil")
   160→	}
   161→
   162→	// Verify this session belongs to Gemini CLI
   163→	if session.AgentName != "" && session.AgentName != g.Name() {
   164→		return fmt.Errorf("session belongs to agent %q, not %q", session.AgentName, g.Name())
   165→	}
   166→
   167→	if session.SessionRef == "" {
   168→		return errors.New("session reference (transcript path) is required")
   169→	}
   170→
   171→	if len(session.NativeData) == 0 {
   172→		return errors.New("session has no native data to write")
   173→	}
   174→
   175→	// Write the raw JSON data
   176→	if err := os.WriteFile(session.SessionRef, session.NativeData, 0o600); err != nil {
   177→		return fmt.Errorf("failed to write transcript: %w", err)
   178→	}
   179→
   180→	return nil
   181→}
