   197→// GetTranscriptPosition returns the current message count of a Gemini transcript.
   198→// Gemini uses JSON format with a messages array, so position is the message count.
   199→// Returns 0 if the file doesn't exist or is empty.
   200→func (g *GeminiCLIAgent) GetTranscriptPosition(path string) (int, error) {
   201→	if path == "" {
   202→		return 0, nil
   203→	}
   204→
   205→	data, err := os.ReadFile(path) //nolint:gosec // Reading from controlled transcript path
   206→	if err != nil {
   207→		if os.IsNotExist(err) {
   208→			return 0, nil
   209→		}
   210→		return 0, fmt.Errorf("failed to read transcript: %w", err)
   211→	}
   212→
   213→	if len(data) == 0 {
   214→		return 0, nil
   215→	}
   216→
   217→	transcript, err := ParseTranscript(data)
   218→	if err != nil {
   219→		return 0, fmt.Errorf("failed to parse transcript: %w", err)
   220→	}
   221→
   222→	return len(transcript.Messages), nil
   223→}
