   225→// ExtractModifiedFilesFromOffset extracts files modified since a given message index.
   226→// For Gemini (JSON format), offset is the starting message index.
   227→// Returns:
   228→//   - files: list of file paths modified by Gemini (from Write/Edit tools)
   229→//   - currentPosition: total number of messages in the transcript
   230→//   - error: any error encountered during reading
   231→func (g *GeminiCLIAgent) ExtractModifiedFilesFromOffset(path string, startOffset int) (files []string, currentPosition int, err error) {
   232→	if path == "" {
   233→		return nil, 0, nil
   234→	}
   235→
   236→	data, readErr := os.ReadFile(path) //nolint:gosec // Reading from controlled transcript path
   237→	if readErr != nil {
   238→		if os.IsNotExist(readErr) {
   239→			return nil, 0, nil
   240→		}
   241→		return nil, 0, fmt.Errorf("failed to read transcript: %w", readErr)
   242→	}
   243→
   244→	if len(data) == 0 {
   245→		return nil, 0, nil
   246→	}
   247→
   248→	transcript, parseErr := ParseTranscript(data)
   249→	if parseErr != nil {
   250→		return nil, 0, parseErr
   251→	}
   252→
   253→	totalMessages := len(transcript.Messages)
   254→
   255→	// Extract files from messages starting at startOffset
   256→	fileSet := make(map[string]bool)
   257→	for i := startOffset; i < len(transcript.Messages); i++ {
   258→		msg := transcript.Messages[i]
   259→		// Only process gemini messages (assistant messages)
   260→		if msg.Type != MessageTypeGemini {
   261→			continue
   262→		}
   263→
   264→		// Process tool calls in this message
   265→		for _, toolCall := range msg.ToolCalls {
   266→			// Check if it's a file modification tool
   267→			isModifyTool := false
   268→			for _, name := range FileModificationTools {
   269→				if toolCall.Name == name {
   270→					isModifyTool = true
   271→					break
   272→				}
   273→			}
   274→
   275→			if !isModifyTool {
   276→				continue
   277→			}
   278→
   279→			// Extract file path from args map
   280→			var file string
   281→			if fp, ok := toolCall.Args["file_path"].(string); ok && fp != "" {
   282→				file = fp
   283→			} else if p, ok := toolCall.Args["path"].(string); ok && p != "" {
   284→				file = p
   285→			} else if fn, ok := toolCall.Args["filename"].(string); ok && fn != "" {
   286→				file = fn
   287→			}
   288→
   289→			if file != "" && !fileSet[file] {
   290→				fileSet[file] = true
   291→				files = append(files, file)
   292→			}
   293→		}
   294→	}
   295→
   296→	return files, totalMessages, nil
   297→}
