   299→// ChunkTranscript splits a Gemini JSON transcript by distributing messages across chunks.
   300→// Gemini uses JSON format with a {"messages": [...]} structure, so chunking splits
   301→// the messages array while preserving the JSON structure in each chunk.
   302→func (g *GeminiCLIAgent) ChunkTranscript(content []byte, maxSize int) ([][]byte, error) {
   303→	var transcript GeminiTranscript
   304→	if err := json.Unmarshal(content, &transcript); err != nil {
   305→		// Fall back to JSONL chunking if not valid Gemini JSON
   306→		chunks, chunkErr := agent.ChunkJSONL(content, maxSize)
   307→		if chunkErr != nil {
   308→			return nil, fmt.Errorf("failed to chunk as JSONL: %w", chunkErr)
   309→		}
   310→		return chunks, nil
   311→	}
   312→
   313→	if len(transcript.Messages) == 0 {
   314→		return [][]byte{content}, nil
   315→	}
   316→
   317→	var chunks [][]byte
   318→	var currentMessages []GeminiMessage
   319→	currentSize := len(`{"messages":[]}`) // Base JSON structure size
   320→
   321→	for i, msg := range transcript.Messages {
   322→		// Marshal message to get its size
   323→		msgBytes, err := json.Marshal(msg)
   324→		if err != nil {
   325→			logging.Warn(context.Background(), "failed to marshal Gemini message during chunking",
   326→				slog.Int("message_index", i),
   327→				slog.String("error", err.Error()),
   328→			)
   329→			continue
   330→		}
   331→		msgSize := len(msgBytes) + 1 // +1 for comma separator
   332→
   333→		if currentSize+msgSize > maxSize && len(currentMessages) > 0 {
   334→			// Save current chunk
   335→			chunkData, err := json.Marshal(GeminiTranscript{Messages: currentMessages})
   336→			if err != nil {
   337→				return nil, fmt.Errorf("failed to marshal chunk: %w", err)
   338→			}
   339→			chunks = append(chunks, chunkData)
   340→
   341→			// Start new chunk
   342→			currentMessages = nil
   343→			currentSize = len(`{"messages":[]}`)
   344→		}
   345→
   346→		currentMessages = append(currentMessages, msg)
   347→		currentSize += msgSize
   348→	}
   349→
   350→	// Add the last chunk
   351→	if len(currentMessages) > 0 {
   352→		chunkData, err := json.Marshal(GeminiTranscript{Messages: currentMessages})
   353→		if err != nil {
   354→			return nil, fmt.Errorf("failed to marshal final chunk: %w", err)
   355→		}
   356→		chunks = append(chunks, chunkData)
   357→	}
   358→
   359→	// Ensure we created at least one chunk (could be empty if all messages failed to marshal)
   360→	if len(chunks) == 0 {
   361→		return nil, errors.New("failed to create any chunks: all messages failed to marshal")
   362→	}
   363→
   364→	return chunks, nil
   365→}
   366→
   367→// ReassembleTranscript merges Gemini JSON chunks by combining their message arrays.
   368→func (g *GeminiCLIAgent) ReassembleTranscript(chunks [][]byte) ([]byte, error) {
   369→	var allMessages []GeminiMessage
   370→
   371→	for _, chunk := range chunks {
   372→		var transcript GeminiTranscript
   373→		if err := json.Unmarshal(chunk, &transcript); err != nil {
   374→			return nil, fmt.Errorf("failed to unmarshal chunk: %w", err)
   375→		}
   376→		allMessages = append(allMessages, transcript.Messages...)
   377→	}
   378→
   379→	result, err := json.Marshal(GeminiTranscript{Messages: allMessages})
   380→	if err != nil {
   381→		return nil, fmt.Errorf("failed to marshal reassembled transcript: %w", err)
   382→	}
   383→	return result, nil
   384→}
