	if len(entries) != 2 {
		t.Fatalf("expected 2 entries, got %d", len(entries))
	}

	if entries[0].Type != EntryTypeUser {
		t.Errorf("entry 0: expected type %s, got %s", EntryTypeUser, entries[0].Type)
