	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "lifecycle"), ag.Name())
	logging.Info(logCtx, "session-end",
		slog.String("event", event.Type.String()),
		slog.String("session_id", event.SessionID),
	)

	if event.SessionID == "" {
		return nil // No session to update
	}

	// Clean up cached transcript before marking session ended
	// (the session state has the transcript path)
	if state, err := strategy.LoadSessionState(event.SessionID); err == nil && state != nil {
		if cleanupErr := CleanupCachedTranscript(state.TranscriptPath); cleanupErr != nil {
			fmt.Fprintf(os.Stderr, "Warning: failed to cleanup cached transcript: %v\n", cleanupErr)
		}
	}

	if err := markSessionEnded(event.SessionID); err != nil {
		fmt.Fprintf(os.Stderr, "Warning: failed to mark session ended: %v\n", err)
	}
	return nil
}

