    55→// ReadTranscript reads the transcript for a session.
    56→// The sessionRef is expected to be a path to the export JSON file.
    57→func (a *OpenCodeAgent) ReadTranscript(sessionRef string) ([]byte, error) {
    58→	data, err := os.ReadFile(sessionRef) //nolint:gosec // Path from agent hook
    59→	if err != nil {
    60→		return nil, fmt.Errorf("failed to read opencode transcript: %w", err)
    61→	}
    62→	return data, nil
    63→}
    64→
    65→// ChunkTranscript splits an OpenCode export JSON transcript by distributing messages across chunks.
    66→// OpenCode uses JSON format with {"info": {...}, "messages": [...]} structure.
    67→func (a *OpenCodeAgent) ChunkTranscript(content []byte, maxSize int) ([][]byte, error) {
    68→	var session ExportSession
    69→	if err := json.Unmarshal(content, &session); err != nil {
    70→		return nil, fmt.Errorf("failed to parse export session for chunking: %w", err)
    71→	}
    72→
    73→	if len(session.Messages) == 0 {
    74→		return [][]byte{content}, nil
    75→	}
    76→
    77→	var chunks [][]byte
    78→	var currentMessages []ExportMessage
    79→	currentSize := len(`{"info":{},"messages":[]}`) // Base JSON structure size
    80→
    81→	for _, msg := range session.Messages {
    82→		// Marshal message to get its size
    83→		msgBytes, err := json.Marshal(msg)
    84→		if err != nil {
    85→			continue
    86→		}
    87→		msgSize := len(msgBytes) + 1 // +1 for comma separator
    88→
    89→		if currentSize+msgSize > maxSize && len(currentMessages) > 0 {
    90→			// Save current chunk
    91→			chunkData, err := json.Marshal(ExportSession{Info: session.Info, Messages: currentMessages})
    92→			if err != nil {
    93→				return nil, fmt.Errorf("failed to marshal chunk: %w", err)
    94→			}
    95→			chunks = append(chunks, chunkData)
    96→
    97→			// Start new chunk
    98→			currentMessages = nil
    99→			currentSize = len(`{"info":{},"messages":[]}`)
   100→		}
   101→
   102→		currentMessages = append(currentMessages, msg)
   103→		currentSize += msgSize
   104→	}
   105→
   106→	// Add the last chunk
   107→	if len(currentMessages) > 0 {
   108→		chunkData, err := json.Marshal(ExportSession{Info: session.Info, Messages: currentMessages})
   109→		if err != nil {
   110→			return nil, fmt.Errorf("failed to marshal final chunk: %w", err)
   111→		}
   112→		chunks = append(chunks, chunkData)
   113→	}
   114→
   115→	if len(chunks) == 0 {
   116→		return nil, errors.New("failed to create any chunks")
   117→	}
   118→
   119→	return chunks, nil
   120→}
   121→
   122→// ReassembleTranscript merges OpenCode export JSON chunks by combining their message arrays.
   123→func (a *OpenCodeAgent) ReassembleTranscript(chunks [][]byte) ([]byte, error) {
   124→	if len(chunks) == 0 {
   125→		return nil, nil
   126→	}
   127→
   128→	var allMessages []ExportMessage
   129→	var sessionInfo SessionInfo
   130→
   131→	for i, chunk := range chunks {
   132→		var session ExportSession
   133→		if err := json.Unmarshal(chunk, &session); err != nil {
   134→			return nil, fmt.Errorf("failed to unmarshal chunk %d: %w", i, err)
   135→		}
   136→		if i == 0 {
   137→			sessionInfo = session.Info // Preserve session info from first chunk
   138→		}
   139→		allMessages = append(allMessages, session.Messages...)
   140→	}
   141→
   142→	result, err := json.Marshal(ExportSession{Info: sessionInfo, Messages: allMessages})
   143→	if err != nil {
   144→		return nil, fmt.Errorf("failed to marshal reassembled transcript: %w", err)
   145→	}
   146→	return result, nil
   147→}
