   156→// Transcripts are ephemeral handoff files between the TS plugin and the Go hook handler.
   157→// Once checkpointed, the data lives on git refs and the file is disposable.
   158→// Stored in os.TempDir()/entire-opencode/<sanitized-path>/ to avoid squatting on
   159→// OpenCode's own directories (~/.opencode/ is project-level, not home-level).
   160→func (a *OpenCodeAgent) GetSessionDir(repoPath string) (string, error) {
   161→	// Check for test environment override
   162→	if override := os.Getenv("ENTIRE_TEST_OPENCODE_PROJECT_DIR"); override != "" {
