   174→func (a *OpenCodeAgent) ReadSession(input *agent.HookInput) (*agent.AgentSession, error) {
   175→	if input.SessionRef == "" {
   176→		return nil, errors.New("no session ref provided")
   177→	}
   178→	data, err := os.ReadFile(input.SessionRef)
   179→	if err != nil {
   180→		return nil, fmt.Errorf("failed to read session: %w", err)
   181→	}
   182→
   183→	// Parse to extract computed fields
   184→	modifiedFiles, err := ExtractModifiedFiles(data)
   185→	if err != nil {
   186→		// Non-fatal: we can still return the session without modified files
   187→		modifiedFiles = nil
   188→	}
   189→
   190→	return &agent.AgentSession{
   191→		AgentName:     a.Name(),
   192→		SessionID:     input.SessionID,
   193→		SessionRef:    input.SessionRef,
   194→		NativeData:    data,
   195→		ExportData:    data, // Export JSON is both native and export format
   196→		ModifiedFiles: modifiedFiles,
   197→	}, nil
   198→}
   199→
   200→func (a *OpenCodeAgent) WriteSession(session *agent.AgentSession) error {
   201→	if session == nil {
   202→		return errors.New("nil session")
   203→	}
   204→	if session.SessionRef == "" {
   205→		return errors.New("no session ref to write to")
   206→	}
   207→	if len(session.NativeData) == 0 {
   208→		return errors.New("no session data to write")
   209→	}
   210→
   211→	// 1. Write JSONL file (for Entire's internal checkpoint use)
   212→	dir := filepath.Dir(session.SessionRef)
   213→	//nolint:gosec // G301: Session directory needs standard permissions
   214→	if err := os.MkdirAll(dir, 0o755); err != nil {
   215→		return fmt.Errorf("failed to create session directory: %w", err)
   216→	}
   217→	if err := os.WriteFile(session.SessionRef, session.NativeData, 0o600); err != nil {
   218→		return fmt.Errorf("failed to write session data: %w", err)
   219→	}
   220→
   221→	// 2. If we have export data, import the session into OpenCode.
   222→	//    This enables `opencode -s <id>` for both resume and rewind.
   223→	if len(session.ExportData) == 0 {
   224→		return nil // No export data — skip import (graceful degradation)
   225→	}
   226→
   227→	if err := a.importSessionIntoOpenCode(session.SessionID, session.ExportData); err != nil {
   228→		// Non-fatal: import is best-effort. The JSONL file is written,
   229→		// and the user can always run `opencode import <file>` manually.
   230→		fmt.Fprintf(os.Stderr, "warning: could not import session into OpenCode: %v\n", err)
   231→	}
   232→
   233→	return nil
   234→}
   235→
   236→// importSessionIntoOpenCode writes the export JSON to a temp file and runs
   237→// `opencode import` to restore the session into OpenCode's database.
   238→// For rewind (session already exists), the session is deleted first so the
   239→// reimport replaces it with the checkpoint-state messages.
   240→func (a *OpenCodeAgent) importSessionIntoOpenCode(sessionID string, exportData []byte) error {
   241→	// Delete the session first so reimport replaces it cleanly.
   242→	// opencode import uses ON CONFLICT DO NOTHING, so existing messages
   243→	// would be skipped without this step (breaking rewind).
   244→	// runOpenCodeSessionDelete treats "not found" as success.
   245→	if err := runOpenCodeSessionDelete(sessionID); err != nil {
   246→		return fmt.Errorf("failed to delete existing session: %w", err)
   247→	}
   248→
   249→	// Write export JSON to a temp file for opencode import
   250→	tmpFile, err := os.CreateTemp("", "entire-opencode-export-*.json")
   251→	if err != nil {
   252→		return fmt.Errorf("failed to create temp file: %w", err)
   253→	}
   254→	defer os.Remove(tmpFile.Name())
   255→
   256→	if _, err := tmpFile.Write(exportData); err != nil {
   257→		_ = tmpFile.Close()
   258→		return fmt.Errorf("failed to write export data: %w", err)
   259→	}
   260→	if err := tmpFile.Close(); err != nil {
   261→		return fmt.Errorf("failed to close temp file: %w", err)
   262→	}
   263→
   264→	return runOpenCodeImport(tmpFile.Name())
   265→}
