   267→func (a *OpenCodeAgent) FormatResumeCommand(sessionID string) string {
   268→	if strings.TrimSpace(sessionID) == "" {
   269→		return "opencode"
   270→	}
   271→	return "opencode -s " + sessionID
   272→}
   273→
   274→// nonAlphanumericRegex matches any non-alphanumeric character.
   275→var nonAlphanumericRegex = regexp.MustCompile(`[^a-zA-Z0-9]`)
   276→
   277→// SanitizePathForOpenCode converts a path to a safe directory name.
   278→// Replaces any non-alphanumeric character with a dash (same approach as Claude/Gemini).
   279→func SanitizePathForOpenCode(path string) string {
   280→	return nonAlphanumericRegex.ReplaceAllString(path, "-")
   281→}
