    19→// ParseExportSession parses export JSON content into an ExportSession structure.
    20→func ParseExportSession(data []byte) (*ExportSession, error) {
    21→	if len(data) == 0 {
    22→		return nil, nil //nolint:nilnil // nil for empty data is expected
    23→	}
    24→
    25→	var session ExportSession
    26→	if err := json.Unmarshal(data, &session); err != nil {
    27→		return nil, fmt.Errorf("failed to parse export session: %w", err)
    28→	}
    29→
    30→	return &session, nil
