    33→// parseExportSessionFromFile reads and parses an export JSON transcript file.
    34→func parseExportSessionFromFile(path string) (*ExportSession, error) {
    35→	data, err := os.ReadFile(path) //nolint:gosec // Path from agent hook
    36→	if err != nil {
    37→		return nil, err //nolint:wrapcheck // Callers check os.IsNotExist on this error
    38→	}
    39→	return ParseExportSession(data)
