    42→// SliceFromMessage returns an OpenCode export transcript scoped to messages starting from
    43→// startMessageIndex. This is the OpenCode equivalent of transcript.SliceFromLine —
    44→// for OpenCode's JSON format, scoping is done by message index rather than line offset.
    45→// Returns the original data if startMessageIndex <= 0.
    46→// Returns nil if startMessageIndex exceeds the number of messages.
    47→func SliceFromMessage(data []byte, startMessageIndex int) []byte {
    48→	if len(data) == 0 || startMessageIndex <= 0 {
    49→		return data
    50→	}
    51→
    52→	session, err := ParseExportSession(data)
    53→	if err != nil || session == nil {
    54→		return nil
    55→	}
    56→
    57→	if startMessageIndex >= len(session.Messages) {
    58→		return nil
    59→	}
    60→
    61→	scoped := &ExportSession{
    62→		Info:     session.Info,
    63→		Messages: session.Messages[startMessageIndex:],
    64→	}
    65→
    66→	out, err := json.Marshal(scoped)
    67→	if err != nil {
    68→		return nil
    69→	}
    70→	return out
    71→}
