    88→// ExtractModifiedFilesFromOffset extracts files modified by tool calls from the given message offset.
    89→func (a *OpenCodeAgent) ExtractModifiedFilesFromOffset(path string, startOffset int) ([]string, int, error) {
    90→	session, err := parseExportSessionFromFile(path)
    91→	if err != nil {
    92→		if os.IsNotExist(err) {
    93→			return nil, 0, nil
    94→		}
    95→		return nil, 0, err
    96→	}
    97→	if session == nil {
    98→		return nil, 0, nil
    99→	}
   100→
   101→	seen := make(map[string]bool)
   102→	var files []string
   103→
   104→	for i := startOffset; i < len(session.Messages); i++ {
   105→		msg := session.Messages[i]
   106→		if msg.Info.Role != roleAssistant {
   107→			continue
   108→		}
