   163→// extractFilePathFromInput extracts the file path from a tool's input map.
   164→func extractFilePathFromInput(input map[string]any) string {
   165→	for _, key := range []string{"file_path", "path", "file", "filename"} {
   166→		if v, ok := input[key]; ok {
   167→			if s, ok := v.(string); ok && s != "" {
   168→				return s
   169→			}
   170→		}
   171→	}
   172→	return ""
   173→}
