   175→// ExtractPrompts extracts user prompt strings from the transcript starting at the given offset.
   176→func (a *OpenCodeAgent) ExtractPrompts(sessionRef string, fromOffset int) ([]string, error) {
   177→	session, err := parseExportSessionFromFile(sessionRef)
   178→	if err != nil {
   179→		if os.IsNotExist(err) {
   180→			return nil, nil
   181→		}
   182→		return nil, err
   183→	}
   184→	if session == nil {
   185→		return nil, nil
   186→	}
   187→
   188→	var prompts []string
   189→	for i := fromOffset; i < len(session.Messages); i++ {
   190→		msg := session.Messages[i]
   191→		if msg.Info.Role != roleUser {
   192→			continue
   193→		}
   194→		// Extract text from parts
   195→		content := extractTextFromParts(msg.Parts)
   196→		if content != "" {
   197→			prompts = append(prompts, content)
   198→		}
   199→	}
   200→
   201→	return prompts, nil
   202→}
