   204→// ExtractSummary extracts the last assistant message content as a summary.
   205→func (a *OpenCodeAgent) ExtractSummary(sessionRef string) (string, error) {
   206→	session, err := parseExportSessionFromFile(sessionRef)
   207→	if err != nil {
   208→		if os.IsNotExist(err) {
   209→			return "", nil
   210→		}
   211→		return "", err
   212→	}
   213→	if session == nil {
   214→		return "", nil
   215→	}
   216→
   217→	for i := len(session.Messages) - 1; i >= 0; i-- {
   218→		msg := session.Messages[i]
   219→		if msg.Info.Role == roleAssistant {
   220→			content := extractTextFromParts(msg.Parts)
   221→			if content != "" {
   222→				return content, nil
   223→			}
   224→		}
   225→	}
   226→
   227→	return "", nil
   228→}
