   230→// extractTextFromParts extracts text content from message parts.
   231→func extractTextFromParts(parts []Part) string {
   232→	var texts []string
   233→	for _, part := range parts {
   234→		if part.Type == "text" && part.Text != "" {
   235→			texts = append(texts, part.Text)
   236→		}
   237→	}
   238→	return strings.Join(texts, "\n")
   239→}
