   265→// CalculateTokenUsageFromBytes computes token usage from raw export JSON transcript bytes
   266→// starting at the given message offset.
   267→// This is a package-level function used by the condensation path (which has bytes, not a file path).
   268→func CalculateTokenUsageFromBytes(data []byte, startMessageIndex int) *agent.TokenUsage {
   269→	session, err := ParseExportSession(data)
   270→	if err != nil || session == nil {
   271→		return &agent.TokenUsage{}
   272→	}
   273→
   274→	usage := &agent.TokenUsage{}
   275→	for i := startMessageIndex; i < len(session.Messages); i++ {
   276→		msg := session.Messages[i]
   277→		if msg.Info.Role != roleAssistant || msg.Info.Tokens == nil {
   278→			continue
   279→		}
   280→		usage.InputTokens += msg.Info.Tokens.Input
   281→		usage.OutputTokens += msg.Info.Tokens.Output
   282→		usage.CacheReadTokens += msg.Info.Tokens.Cache.Read
   283→		usage.CacheCreationTokens += msg.Info.Tokens.Cache.Write
   284→		usage.APICallCount++
   285→	}
   286→
   287→	return usage
   288→}
