   290→// CalculateTokenUsage computes token usage from assistant messages starting at the given offset.
   291→func (a *OpenCodeAgent) CalculateTokenUsage(sessionRef string, fromOffset int) (*agent.TokenUsage, error) {
   292→	session, err := parseExportSessionFromFile(sessionRef)
   293→	if err != nil {
   294→		if os.IsNotExist(err) {
   295→			return nil, nil //nolint:nilnil // nil usage for nonexistent file is expected
   296→		}
   297→		return nil, fmt.Errorf("failed to parse transcript for token usage: %w", err)
   298→	}
   299→	if session == nil {
   300→		return nil, nil //nolint:nilnil // nil usage for empty file is expected
   301→	}
   302→
   303→	usage := &agent.TokenUsage{}
   304→	for i := fromOffset; i < len(session.Messages); i++ {
   305→		msg := session.Messages[i]
   306→		if msg.Info.Role != roleAssistant || msg.Info.Tokens == nil {
   307→			continue
   308→		}
   309→		usage.InputTokens += msg.Info.Tokens.Input
   310→		usage.OutputTokens += msg.Info.Tokens.Output
   311→		usage.CacheReadTokens += msg.Info.Tokens.Cache.Read
   312→		usage.CacheCreationTokens += msg.Info.Tokens.Cache.Write
   313→		usage.APICallCount++
   314→	}
   315→
   316→	return usage, nil
   317→}
