   621→// resolveTranscriptOffset determines the transcript offset to use for parsing.
   622→// Prefers pre-prompt state, falls back to session state.
   623→func resolveTranscriptOffset(preState *PrePromptState, sessionID string) int {
   624→	if preState != nil && preState.TranscriptOffset > 0 {
   625→		fmt.Fprintf(os.Stderr, "Pre-prompt state found: parsing transcript from offset %d\n", preState.TranscriptOffset)
   626→		return preState.TranscriptOffset
   627→	}
   628→
   629→	// Fall back to session state (e.g., auto-commit strategy updates it after each save)
   630→	sessionState, loadErr := strategy.LoadSessionState(sessionID)
   631→	if loadErr != nil {
   632→		fmt.Fprintf(os.Stderr, "Warning: failed to load session state: %v\n", loadErr)
   633→		return 0
   634→	}
   635→	if sessionState != nil && sessionState.CheckpointTranscriptStart > 0 {
   636→		fmt.Fprintf(os.Stderr, "Session state found: parsing transcript from offset %d\n", sessionState.CheckpointTranscriptStart)
   637→		return sessionState.CheckpointTranscriptStart
   638→	}
   639→
   640→	return 0
   641→}
