   704→// transitionSessionTurnEnd transitions the session phase to IDLE and dispatches turn-end actions.
   705→func transitionSessionTurnEnd(sessionID string) {
   706→	turnState, loadErr := strategy.LoadSessionState(sessionID)
   707→	if loadErr != nil {
   708→		fmt.Fprintf(os.Stderr, "Warning: failed to load session state for turn end: %v\n", loadErr)
   709→		return
   710→	}
   711→	if turnState == nil {
   712→		return
   713→	}
   714→	if err := strategy.TransitionAndLog(turnState, session.EventTurnEnd, session.TransitionContext{}, session.NoOpActionHandler{}); err != nil {
   715→		fmt.Fprintf(os.Stderr, "Warning: turn-end transition failed: %v\n", err)
   716→	}
   717→
   718→	// Always dispatch to strategy for turn-end handling. The strategy reads
   719→	// work items from state (e.g. TurnCheckpointIDs), not the action list.
   720→	strat := GetStrategy()
   721→	if handler, ok := strat.(strategy.TurnEndHandler); ok {
   722→		if err := handler.HandleTurnEnd(turnState); err != nil {
   723→			fmt.Fprintf(os.Stderr, "Warning: turn-end action dispatch failed: %v\n", err)
   724→		}
   725→	}
   726→
   727→	if updateErr := strategy.SaveSessionState(turnState); updateErr != nil {
   728→		fmt.Fprintf(os.Stderr, "Warning: failed to update session phase on turn end: %v\n", updateErr)
   729→	}
   730→}
