   732→// markSessionEnded transitions the session to ENDED phase via the state machine.
   733→func markSessionEnded(sessionID string) error {
   734→	state, err := strategy.LoadSessionState(sessionID)
   735→	if err != nil {
   736→		return fmt.Errorf("failed to load session state: %w", err)
   737→	}
   738→	if state == nil {
   739→		return nil // No state file, nothing to update
   740→	}
   741→
   742→	if transErr := strategy.TransitionAndLog(state, session.EventSessionStop, session.TransitionContext{}, session.NoOpActionHandler{}); transErr != nil {
   743→		fmt.Fprintf(os.Stderr, "Warning: session stop transition failed: %v\n", transErr)
   744→	}
   745→
   746→	now := time.Now()
   747→	state.EndedAt = &now
   748→
   749→	if err := strategy.SaveSessionState(state); err != nil {
   750→		return fmt.Errorf("failed to save session state: %w", err)
   751→	}
   752→	return nil
   753→}
